def get_catalog():
    result = []
    for item in RAW_CATALOG:
        first_key = item["keys"][0] if item["keys"] else "K"
        test_type = KEY_MAP.get(first_key, "K")
        result.append({
            "name": item["name"],
            "url": item["link"],
            "test_type": test_type,
            "description": item["description"],
            "job_levels": item["job_levels"],
            "duration": item["duration"],
            "keys": item["keys"],
            "entity_id": item["entity_id"],
            "remote": item["remote"],
            "adaptive": item["adaptive"],
        })
    return result


def build_catalog_text():
    lines = []
    for item in RAW_CATALOG:
        keys_str = ", ".join(item["keys"])
        levels_str = ", ".join(item["job_levels"]) if item["job_levels"] else "All levels"
        dur = item["duration"] or "varies"
        lines.append(
            f"- {item['name']} | {keys_str} | {levels_str} | {dur} | {item['link']}\n"
            f"  {item['description'][:200]}"
        )
    return "\n".join(lines)
